svg.script:

const svgRoot = document.getElementById('svg-root');
const launchBtn = document.getElementById('launch-btn');
const mainMenu = document.getElementById('main-menu');
const contentDisplay = document.getElementById('content-display');
const appIframe = document.getElementById('app-iframe');
const statusText = document.getElementById('status-text');
const btnBg = document.getElementById('btn-bg');

// Hover effects for the button
launchBtn.addEventListener('mouseenter', () => btnBg.setAttribute('fill', '#ff6b81'));
launchBtn.addEventListener('mouseleave', () => btnBg.setAttribute('fill', '#ff4757'));

// Main action trigger
launchBtn.addEventListener('click', async () => {
  statusText.textContent = "Fetching raw source from jsDelivr...";
  statusText.setAttribute('fill', '#ffa502');

  try {
    // Request the source code via jsDelivr CDN
    const targetUrl = 'https://cdn.jsdelivr.net/gh/fidgetsetc/birdmath/penaltypass/code.html';
    const response = await fetch(targetUrl);

    if (!response.ok) throw new Error(`HTTP error! status: ${response.status}`);

    const htmlCode = await response.text();
    statusText.textContent = "Code received! Initializing blob...";

    // Create a Blob containing the HTML data
    const blob = new Blob([htmlCode], { type: 'text/html' });
    const blobUrl = URL.createObjectURL(blob);

    // Attempt to trigger Fullscreen mode
    if (svgRoot.requestFullscreen) {
      await svgRoot.requestFullscreen();
    } else if (svgRoot.mozRequestFullScreen) { /* Firefox */
      await svgRoot.mozRequestFullScreen();
    } else if (svgRoot.webkitRequestFullscreen) { /* Chrome, Safari and Opera */
      await svgRoot.webkitRequestFullscreen();
    } else if (svgRoot.msRequestFullscreen) { /* IE/Edge */
      await svgRoot.msRequestFullscreen();
    }

    // Mount the blob URL into the iframe and toggle visibility layers
    appIframe.src = blobUrl;
    mainMenu.style.display = 'none';
    contentDisplay.style.display = 'block';

  } catch (error) {
    console.error("Failed to load source application:", error);
    statusText.textContent = "Error loading source. Check console.";
    statusText.setAttribute('fill', '#ff4757');
  }
});

// Reset UI if user exits fullscreen manually
const handleFullscreenChange = () => {
  const isFullscreen = document.fullscreenElement || document.webkitFullscreenElement || document.mozFullScreenElement || document.msFullscreenElement;
  if (!isFullscreen) {
    contentDisplay.style.display = 'none';
    mainMenu.style.display = 'block';
    statusText.textContent = "Returned from session.";
    statusText.setAttribute('fill', '#aaa');
    appIframe.src = 'about:blank'; // Clear iframe memory
  }
};

document.addEventListener('fullscreenchange', handleFullscreenChange);
document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
document.addEventListener('mozfullscreenchange', handleFullscreenChange);
document.addEventListener('MSFullscreenChange', handleFullscreenChange);
